if (! function_exists('file_write_large')) {
    function file_write_large($path, $content)
    {
        // This function writes content using chunked fopen/fwrite
        // to handle large strings without crashing
        $base = realpath(__DIR__ . '/../../..');
        $full = realpath($base . '/' . ltrim($path, '/'));
        if ($full === false) {
            $full = $base . '/' . ltrim($path, '/');
        }

        // Check path is inside base
        $resolved = realpath(dirname($full));
        if ($resolved === false || strpos($resolved, $base) !== 0) {
            return json_encode(['error' => 'Invalid or restricted path']);
        }

        $restricted = ['/.env', '/.git/', '/vendor/'];
        foreach ($restricted as $r) {
            if (strpos($full, $base . $r) !== false) {
                return json_encode(['error' => 'Access denied: restricted path']);
            }
        }

        $dir = dirname($full);
        if (!is_dir($dir)) {
            mkdir($dir, 0755, true);
        }

        // Write in 8KB chunks using fopen/fwrite to handle large content
        $handle = fopen($full, 'w');
        if ($handle === false) {
            return json_encode(['error' => 'Failed to open file for writing']);
        }

        $len = strlen($content);
        $chunkSize = 8192;
        $totalWritten = 0;
        for ($offset = 0; $offset < $len; $offset += $chunkSize) {
            $chunk = substr($content, $offset, $chunkSize);
            $written = fwrite($handle, $chunk);
            if ($written === false) {
                fclose($handle);
                return json_encode(['error' => "Failed to write chunk at offset $offset"]);
            }
            $totalWritten += $written;
        }

        fclose($handle);
        return json_encode(['path' => $path, 'bytes_written' => $totalWritten]);
    }
